import { classNames } from '#utils/UNSAFE_classNames';
import { usePressClick } from '#hooks/UNSAFE_usePressClick';
import { useComponentTheme } from '#hooks/UNSAFE_useComponentTheme';
import { LinkVariantOptions } from '#UNSAFE_Link/themes/LinkStyles.css';
import { useInteractionStyle } from '#hooks/UNSAFE_useInteractionStyle';
import { LinkRedwoodTheme } from '#UNSAFE_Link/themes/redwood/LinkTheme';
import { useTabbableMode } from '#hooks/UNSAFE_useTabbableMode';
import { useTestId, TestIdProps } from '#hooks/UNSAFE_useTestId';
import { useDetectTruncation } from '#hooks/PRIVATE_useDetectTruncation';
import { useTooltip } from '#hooks/UNSAFE_useTooltip';
import { mergeProps } from '#utils/UNSAFE_mergeProps';
import { getClientHints } from '#utils/PRIVATE_clientHints';
import { UnpackSignals } from '#utils/UNSAFE_attributeUtils';
import type { JSX } from 'preact';
import { Text } from '#UNSAFE_Text';
import { MiddleTruncatingLink } from './MiddleTruncatingLink';

type AriaProps = Pick<
  UnpackSignals<JSX.AriaAttributes>,
  'aria-describedby' | 'aria-label' | 'aria-labelledby'
>;

type TruncateProps =
  | {
      /**
       * Truncates link at a specific number of lines and then displays an ellipsis (…) at the end of the last line. Parent of the element needs to have a specific width so text starts overflowing and produce a truncation.
       */
      lineClamp?: number;
      /**
       * Determines ellipsis position when link is truncated. Be aware of setting either lineClamp or truncation. Setting both props would produce a type error. In most cases, lineClamp=1 tries to put the ellipsis at the end of a "word". On the other hand, using truncation="end" will show as much as possible text, then put the ellipsis at the end.
       */
      truncation?: never;
    }
  | {
      lineClamp?: never;
      truncation?: 'end' | 'middle' | 'none';
    };

type Props = {
  /**
   * Sets the URL that the hyperlink points to.
   */
  href: string;

  /**
   * Sets the variant. The default value of this property is theme driven.
   */
  variant?: 'standard' | 'primary' | 'secondary';

  /**
   * Sets the placement.
   */
  placement?: 'standalone' | 'embedded';

  /**
   * Sets the target.
   */
  target?: string;

  /**
   * Triggered when a link is clicked, whether by keyboard, mouse, or touch events.
   */
  onClick?: (event: Event) => void;

  /**
   * Specifies that the link element should be disabled.
   */
  isDisabled?: boolean;

  /**
   * Specifies alternative text to be shown rather than the href.
   */
  children?: string;
} & TestIdProps &
  AriaProps &
  TruncateProps;

const noop = () => {};

/**
 * TruncatingLink component creates a hyperlink that shows a tooltip and ellipsis at the end or middle of text when truncated.
 */
export function TruncatingLink({
  href,
  variant,
  placement = 'standalone',
  target,
  testId,
  'aria-describedby': ariaDescribedBy,
  'aria-label': accessibleLabel,
  'aria-labelledby': ariaLabelledBy,
  onClick,
  isDisabled,
  truncation,
  lineClamp,
  children
}: Props) {
  const { detectTruncationProps, isTextTruncated } = useDetectTruncation<HTMLAnchorElement>();
  const { interactionProps, applyPseudoHoverStyle, applyHoverStyle } = useInteractionStyle();
  const clientHints = getClientHints();
  const { classes } = useComponentTheme<LinkVariantOptions>(LinkRedwoodTheme, {
    needsEventsHover: applyHoverStyle ? 'isNeedsEventsHover' : 'notNeedsEventsHover',
    pseudoHover: applyPseudoHoverStyle ? 'isPseudoHover' : 'notPseudoHover',
    variant,
    placement,
    disabled: isDisabled ? 'isDisabled' : 'notDisabled',
    truncatingLinkStyles: placement !== 'embedded' ? 'styles' : 'none',
    truncatingLinkWhiteSpace: placement !== 'embedded' && !lineClamp ? 'nowrap' : 'none',
    safariStyles: clientHints.browser === 'safari' ? 'isSafari' : 'notSafari'
  });
  const { isTabbable } = useTabbableMode();
  const linkClasses = classNames([classes]);
  const { pressProps } = usePressClick(onClick ?? noop);
  const testIdProps = useTestId(testId);
  const shownText = children || href;

  const { tooltipContent, tooltipProps } = useTooltip({
    text: shownText,
    isDisabled: !isTextTruncated || isDisabled
  });
  const { 'aria-describedby': notNeeded, ...validTooltipProps } = tooltipProps; //remove aria-describedby to prevent screen readers reading the same text multiple times

  return truncation === 'middle' ? (
    <MiddleTruncatingLink
      href={href}
      aria-describedby={ariaDescribedBy}
      aria-label={accessibleLabel}
      aria-labelledby={ariaLabelledBy}
      target={target}
      placement={placement}
      isDisabled={isDisabled}
      variant={variant}
      testId={testId}
      onClick={onClick}>
      {shownText}
    </MiddleTruncatingLink>
  ) : (
    <>
      <a
        {...mergeProps(
          detectTruncationProps,
          validTooltipProps,
          interactionProps,
          testIdProps,
          !isDisabled ? pressProps : {}
        )}
        tabIndex={isTabbable && !isDisabled ? 0 : -1}
        href={!isDisabled ? href : undefined}
        aria-describedby={ariaDescribedBy}
        aria-label={accessibleLabel}
        aria-labelledby={ariaLabelledBy}
        target={target}
        class={linkClasses}>
        {lineClamp ? (
          <Text lineClamp={lineClamp} size="md" variant="inherit">
            {shownText}
          </Text>
        ) : (
          <Text
            truncation={truncation === 'end' && placement !== 'embedded' ? 'ellipsis' : undefined}
            size="md"
            variant="inherit">
            {shownText}
          </Text>
        )}
      </a>
      {tooltipContent}
    </>
  );
}
